91	export const nostrSetupAdapter: ChannelSetupAdapter = {
92	  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
93	  applyAccountName: ({ cfg, name }) =>
94	    patchTopLevelChannelConfigSection({
95	      cfg,
96	      channel,
97	      patch: name?.trim() ? { name: name.trim() } : {},
98	    }),
99	  validateInput: ({ input }) => {
100	    const typedInput = input as {
101	      useEnv?: boolean;
102	      privateKey?: string;
103	      relayUrls?: string;
104	    };
105	    if (!typedInput.useEnv) {
106	      const privateKey = typedInput.privateKey?.trim();
107	      if (!privateKey) {
108	        return "Nostr requires --private-key or --use-env.";
109	      }
110	      try {
111	        getPublicKeyFromPrivate(privateKey);
112	      } catch {
113	        return "Nostr private key must be valid nsec or 64-character hex.";
114	      }
115	    }
116	    if (typedInput.relayUrls?.trim()) {
117	      return parseRelayUrls(typedInput.relayUrls).error ?? null;
118	    }
119	    return null;
120	  },
121	  applyAccountConfig: ({ cfg, input }) => {
122	    const typedInput = input as {
123	      useEnv?: boolean;
124	      privateKey?: string;
125	      relayUrls?: string;
126	    };
127	    const relayResult = typedInput.relayUrls?.trim()
128	      ? parseRelayUrls(typedInput.relayUrls)
129	      : { relays: [] };
130	    return patchTopLevelChannelConfigSection({
131	      cfg,
132	      channel,
133	      enabled: true,
134	      clearFields: typedInput.useEnv ? ["privateKey"] : undefined,
135	      patch: {
136	        ...(typedInput.useEnv ? {} : { privateKey: typedInput.privateKey?.trim() }),
137	        ...(relayResult.relays.length > 0 ? { relays: relayResult.relays } : {}),
138	      },
