60	function parseNostrAllowFrom(raw: string): { entries: string[]; error?: string } {
61	  return parseSetupEntriesWithParser(raw, (entry) => {
62	    const cleaned = entry.replace(/^nostr:/i, "").trim();
63	    try {
64	      return { value: normalizePubkey(cleaned) };
65	    } catch {
66	      return { error: `Invalid Nostr pubkey: ${entry}` };
67	    }
68	  });
69	}
