64	export function formatIrcSenderId(message: IrcInboundMessage): string {
65	  const base = message.senderNick.trim();
66	  const user = message.senderUser?.trim();
67	  const host = message.senderHost?.trim();
68	  if (user && host) {
69	    return `${base}!${user}@${host}`;
70	  }
71	  if (user) {
72	    return `${base}!${user}`;
73	  }
74	  if (host) {
75	    return `${base}@${host}`;
76	  }
77	  return base;
78	}
79	
80	export function buildIrcAllowlistCandidates(
81	  message: IrcInboundMessage,
82	  params?: { allowNameMatching?: boolean },
83	): string[] {
84	  const nick = message.senderNick.trim().toLowerCase();
85	  const user = message.senderUser?.trim().toLowerCase();
86	  const host = message.senderHost?.trim().toLowerCase();
87	  const candidates = new Set<string>();
88	  if (nick && params?.allowNameMatching === true) {
89	    candidates.add(nick);
90	  }
91	  if (nick && user) {
92	    candidates.add(`${nick}!${user}`);
93	  }
94	  if (nick && host) {
95	    candidates.add(`${nick}@${host}`);
96	  }
97	  if (nick && user && host) {
98	    candidates.add(`${nick}!${user}@${host}`);
99	  }
100	  return [...candidates];
101	}
102	
103	export function resolveIrcAllowlistMatch(params: {
104	  allowFrom: string[];
105	  message: IrcInboundMessage;
106	  allowNameMatching?: boolean;
107	}): { allowed: boolean; source?: string } {
108	  const allowFrom = new Set(
109	    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
110	  );
111	  if (allowFrom.has("*")) {
112	    return { allowed: true, source: "wildcard" };
113	  }
114	  const candidates = buildIrcAllowlistCandidates(params.message, {
115	    allowNameMatching: params.allowNameMatching,
116	  });
117	  for (const candidate of candidates) {
118	    if (allowFrom.has(candidate)) {
119	      return { allowed: true, source: candidate };
120	    }
121	  }
122	  return { allowed: false };
123	}
