1	export function normalizeMattermostMessagingTarget(raw: string): string | undefined {
2	  const trimmed = raw.trim();
3	  if (!trimmed) {
4	    return undefined;
5	  }
6	  const lower = trimmed.toLowerCase();
7	  if (lower.startsWith("channel:")) {
8	    const id = trimmed.slice("channel:".length).trim();
9	    return id ? `channel:${id}` : undefined;
10	  }
11	  if (lower.startsWith("group:")) {
12	    const id = trimmed.slice("group:".length).trim();
13	    return id ? `channel:${id}` : undefined;
14	  }
15	  if (lower.startsWith("user:")) {
16	    const id = trimmed.slice("user:".length).trim();
17	    return id ? `user:${id}` : undefined;
18	  }
19	  if (lower.startsWith("mattermost:")) {
20	    const id = trimmed.slice("mattermost:".length).trim();
21	    return id ? `user:${id}` : undefined;
22	  }
23	  if (trimmed.startsWith("@")) {
24	    const id = trimmed.slice(1).trim();
25	    return id ? `@${id}` : undefined;
26	  }
27	  if (trimmed.startsWith("#")) {
28	    // Strip # prefix and fall through to directory lookup (same as bare names).
29	    // The core's resolveMessagingTarget will use the directory adapter to
30	    // resolve the channel name to its Mattermost ID.
31	    return undefined;
32	  }
33	  // Bare name without prefix — return undefined to allow directory lookup
34	  return undefined;
35	}
