### `extensions/pulseboard/src/config-schema.ts`

**Purpose:** Zod schema + JSON Schema for the `channels.pulseboard.*` config section.

**Imports:**
```typescript
import {
  AllowFromListSchema,
  DmPolicySchema,
  MarkdownConfigSchema,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { buildChannelConfigSchema } from "openclaw/plugin-sdk/channel-config-schema";
import { z } from "openclaw/plugin-sdk/zod";
```

**Schema structure:**

```typescript
const PulseBoardBoardConfigSchema = z.object({
  requireMention: z.boolean().optional(),
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  enabled: z.boolean().optional(),
}).strict();

export const PulseBoardConfigSchema = z.object({
  name:           z.string().optional(),
  defaultAccount: z.string().optional(),
  enabled:        z.boolean().optional(),
  apiKey:         buildSecretInputSchema().optional(),
  serverUrl:      z.string().url().optional(),
  username:       z.string().optional(),
  dmPolicy:       DmPolicySchema.optional(),
  allowFrom:      AllowFromListSchema,
  boards:         z.record(z.string(), PulseBoardBoardConfigSchema.optional()).optional(),
  markdown:       MarkdownConfigSchema,
}).strict();

export type PulseBoardConfig = z.infer<typeof PulseBoardConfigSchema>;

export const PulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema);
```

Notes:
- `boards` is a map of `#board-name` → per-board config overrides.
- `DmPolicySchema` from `channel-config-primitives` gives `"pairing" | "allowlist" | "open" | "disabled"`.
- `AllowFromListSchema` allows `Array<string | number>`.
- `MarkdownConfigSchema` aligns with the other plugins' markdown table config.
- `.strict()` on all objects prevents unknown keys from passing validation.

