### `extensions/pulseboard/src/accounts.ts`

**Purpose:** Account resolution logic: reads config + env vars, returns `ResolvedPulseBoardAccount`.

**Imports:**
```typescript
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../runtime-api.js";
import type { PulseBoardAccountConfig, ResolvedPulseBoardAccount } from "./types.js";
```

**Key functions:**

```typescript
// Helper: get the raw channels.pulseboard config section
function getPulseBoardCfg(cfg: OpenClawConfig): PulseBoardAccountConfig | undefined {
  return (cfg.channels as Record<string, unknown> | undefined)
    ?.pulseboard as PulseBoardAccountConfig | undefined;
}

// Returns the configured defaultAccount override if any
function resolveConfiguredDefaultAccountId(cfg: OpenClawConfig): string | undefined {
  return normalizeOptionalAccountId(getPulseBoardCfg(cfg)?.defaultAccount);
  // normalizeOptionalAccountId comes from openclaw/plugin-sdk/account-id
}

/**
 * List configured PulseBoard account IDs.
 * Returns ["default"] if apiKey+serverUrl+username are all present, [] otherwise.
 */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = getPulseBoardCfg(cfg);
  const apiKey = resolveApiKey(pbCfg);
  const serverUrl = resolveServerUrl(pbCfg);
  const username = resolveUsername(pbCfg);
  const configured = Boolean(apiKey && serverUrl && username);
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: configured
      ? (resolveConfiguredDefaultAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultAccountId(cfg),
  });
}

/**
 * Resolve API key: config first, then PULSEBOARD_API_KEY env var (default account only).
 */
function resolveApiKey(pbCfg: PulseBoardAccountConfig | undefined, accountId?: string): string {
  const fromConfig = normalizeSecretInputString(pbCfg?.apiKey);
  if (fromConfig) return fromConfig;
  if (!accountId || accountId === DEFAULT_ACCOUNT_ID) {
    return process.env.PULSEBOARD_API_KEY?.trim() ?? "";
  }
  return "";
}

/**
 * Resolve server URL: config first, then PULSEBOARD_SERVER_URL env var.
 */
function resolveServerUrl(pbCfg: PulseBoardAccountConfig | undefined, accountId?: string): string {
  const fromConfig = pbCfg?.serverUrl?.trim();
  if (fromConfig) return fromConfig;
  if (!accountId || accountId === DEFAULT_ACCOUNT_ID) {
    return process.env.PULSEBOARD_SERVER_URL?.trim() ?? "";
  }
  return "";
}

/**
 * Resolve username: config first, then PULSEBOARD_USERNAME env var.
 */
function resolveUsername(pbCfg: PulseBoardAccountConfig | undefined, accountId?: string): string {
  const fromConfig = pbCfg?.username?.trim();
  if (fromConfig) return fromConfig;
  if (!accountId || accountId === DEFAULT_ACCOUNT_ID) {
    return process.env.PULSEBOARD_USERNAME?.trim() ?? "";
  }
  return "";
}

export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg));
  const pbCfg = getPulseBoardCfg(opts.cfg);

  const apiKey = resolveApiKey(pbCfg, accountId);
  const serverUrl = resolveServerUrl(pbCfg, accountId);
  const username = resolveUsername(pbCfg, accountId);
  const configured = Boolean(apiKey && serverUrl && username);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: pbCfg?.enabled !== false,
    configured,
    apiKey,
    serverUrl,
    username,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      apiKey: pbCfg?.apiKey,
      serverUrl: pbCfg?.serverUrl,
      username: pbCfg?.username,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
      boards: pbCfg?.boards,
      markdown: pbCfg?.markdown,
    },
  };
}
```

Env var support is limited to the default account only — same pattern as IRC (`process.env.IRC_HOST` only for `accountId === DEFAULT_ACCOUNT_ID`).

