### `extensions/pulseboard/src/normalize.ts`

**Purpose:** Target normalization, `looksLike`, board detection helpers, and allow-entry normalization.

**Imports:**
```typescript
// No SDK imports needed here — all pure string logic
```

**Key functions:**

```typescript
/**
 * Returns true if the target is a board target (starts with #).
 */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalize a raw target string to its canonical form.
 *
 * - "#board-name" → "#board-name" (lowercase, trimmed)
 * - "@username"   → "@username"   (lowercased, kept with @)
 * - "username"    → "username"    (bare username, kept as-is)
 *
 * Returns undefined if the input is empty or invalid.
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;

  // Strip pulseboard: scheme if present
  const stripped = trimmed.replace(/^pulseboard:/i, "").trim();
  if (!stripped) return undefined;

  if (stripped.startsWith("#")) {
    // Board: normalize to lowercase, validate chars
    const boardName = stripped.slice(1).trim().toLowerCase();
    if (!boardName || !/^[\w-]+$/.test(boardName)) return undefined;
    return `#${boardName}`;
  }

  // User: strip @ prefix for storage, but accept "@username" input
  const username = stripped.startsWith("@") ? stripped.slice(1).trim() : stripped.trim();
  if (!username || !/^[\w.-]+$/.test(username)) return undefined;
  return username;
}

/**
 * Returns true if the raw string looks like a PulseBoard target ID
 * (either #board-name or @username or bare username).
 */
export function looksLikePulseBoardTarget(raw: string): boolean {
  return normalizePulseBoardTarget(raw) !== undefined;
}

/**
 * Normalize an allow-from entry to its canonical form (used in allowlists).
 * Returns null if invalid, "*" for wildcard.
 */
export function normalizePulseBoardAllowEntry(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) return null;
  if (trimmed === "*") return "*";

  // Strip pulseboard: prefix
  const stripped = trimmed.replace(/^pulseboard:/i, "").replace(/^@/, "").trim().toLowerCase();
  if (!stripped) return null;
  return !/^[\w.-]+$/.test(stripped) ? null : stripped;
}
```

Design rationale:
- PulseBoard boards use `#board-name` syntax (same as IRC channels).
- DM targets are bare usernames or `@username` — the `@` is stripped for canonical storage.
- `looksLikePulseBoardTarget` is the `targetResolver.looksLikeId` function.
- The hint shown to users is `"<#board-name|@username>"`.

