### `extensions/pulseboard/src/send.ts`

**Purpose:** Outbound send implementation. Stubs the actual HTTP call since the platform is fictional.

**Imports:**
```typescript
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import type { OpenClawConfig } from "../runtime-api.js";
import { DEFAULT_ACCOUNT_ID } from "../runtime-api.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import { isBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
```

**Key function:**

```typescript
export type SendPulseBoardResult = {
  to: string;
  messageId: string;
};

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: { cfg?: OpenClawConfig; accountId?: string } = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = opts.cfg ?? (runtime.config.loadConfig() as OpenClawConfig);
  const accountId = opts.accountId ?? DEFAULT_ACCOUNT_ID;
  const account = resolvePulseBoardAccount({ cfg, accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${accountId}" (need apiKey, serverUrl, and username).`,
    );
  }

  // Apply markdown table conversion
  const tableMode = runtime.channel.text.resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId,
  });
  const prepared = runtime.channel.text.convertMarkdownTables(text ?? "", tableMode);

  // Stub: In a real implementation, this would POST to the PulseBoard API.
  // POST ${account.serverUrl}/api/send
  // Authorization: Bearer ${account.apiKey}
  // Body: { from: account.username, to, text: prepared }
  const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

  // Record outbound activity
  runtime.channel.activity.record({
    channel: "pulseboard",
    accountId,
    direction: "outbound",
  });

  return attachChannelToResult("pulseboard", { to, messageId });
}
```

