### `extensions/pulseboard/src/monitor.ts`

**Purpose:** Passive inbound monitor stub. Uses `runStoppablePassiveMonitor` from `extension-shared` as the loop wrapper. Since PulseBoard is fictional, the actual WebSocket connection is a no-op placeholder.

**Imports:**
```typescript
import { runStoppablePassiveMonitor } from "openclaw/plugin-sdk/extension-shared";
import type { OpenClawConfig } from "../runtime-api.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { PulseBoardInboundMessage, ResolvedPulseBoardAccount } from "./types.js";
```

**Type and function:**

```typescript
export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: OpenClawConfig;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

/**
 * Placeholder monitor for the PulseBoard WebSocket feed.
 *
 * In a real implementation this would open a WebSocket connection to
 * `${account.serverUrl}/ws?token=${account.apiKey}` and stream inbound
 * messages, calling `onMessage` for each one.  Since PulseBoard is a
 * fictional platform we use a no-op loop that respects the AbortSignal.
 */
export async function monitorPulseBoardAccount(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as OpenClawConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiKey, serverUrl, and username).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  logger.info(
    `[${account.accountId}] PulseBoard monitor started (stub). ` +
    `Would connect to: ${account.serverUrl} as ${account.username}`,
  );

  // Stub: real implementation would establish a WebSocket here and loop.
  // The returned stop() is called by runStoppablePassiveMonitor on abort.
  return {
    stop: () => {
      logger.info(`[${account.accountId}] PulseBoard monitor stopped`);
    },
  };
}
```

Note: `monitorPulseBoardAccount` is called from `channel.ts`'s `gateway.startAccount` via `runStoppablePassiveMonitor`. The `runStoppablePassiveMonitor` call handles abort signal management:

```typescript
await runStoppablePassiveMonitor({
  abortSignal: ctx.abortSignal,
  start: async () =>
    await monitorPulseBoardAccount({
      accountId: account.accountId,
      config: ctx.cfg as OpenClawConfig,
      abortSignal: ctx.abortSignal,
      statusSink,
    }),
});
```

