**Plugin assembly:**

```typescript
export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin Board)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging with boards (#board-name) and direct messages.",
      order: 60,
      quickstartAllowFrom: true,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: PulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            username: account.username,
          },
        }),
    },
    groups: {
      resolveRequireMention: ({ cfg, accountId, groupId }) => {
        if (!groupId) return true;
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.config.boards?.[groupId]?.requireMention !== false;
      },
      resolveToolPolicy: () => undefined, // No per-board tool policy in MVP
    },
    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: looksLikePulseBoardTarget,
        hint: "<#board-name|@username>",
      },
    },
    resolver: {
      resolveTargets: async ({ inputs, kind }) => {
        return inputs.map((input) => {
          const normalized = normalizePulseBoardTarget(input);
          if (!normalized) {
            return { input, resolved: false, note: "invalid PulseBoard target" };
          }
          if (kind === "group") {
            if (!isBoardTarget(normalized)) {
              return { input, resolved: false, note: "expected board target (#board-name)" };
            }
            return { input, resolved: true, id: normalized, name: normalized };
          }
          if (isBoardTarget(normalized)) {
            return { input, resolved: false, note: "expected user target" };
          }
          return { input, resolved: true, id: normalized, name: normalized };
        });
      },
    },
    directory: createChannelDirectoryAdapter({
      listPeers: async (params) => listPulseBoardDirectoryPeers(params),
      listGroups: async (params) => {
        const entries = await listPulseBoardDirectoryGroups(params);
        return entries.map((entry) => ({ ...entry, name: entry.id }));
      },
    }),
    status: {
      ...createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        collectStatusIssues: (accounts) => collectStatusIssuesFromLastError("pulseboard", accounts),
        buildChannelSummary: ({ snapshot }) =>
          buildPassiveChannelStatusSummary(snapshot, {
            serverUrl: snapshot.serverUrl ?? null,
            username: snapshot.username ?? null,
          }),
        resolveAccountSnapshot: ({ account, runtime }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            username: account.username,
            ...buildTrafficStatusSummary(runtime),
          },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        ctx.setStatus({
          accountId: account.accountId,
          serverUrl: account.serverUrl,
          username: account.username,
        });
        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (${account.serverUrl} as ${account.username})`,
        );

        if (!account.configured) {
          throw new Error("PulseBoard is not configured (need apiKey, serverUrl, and username).");
        }

        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () =>
            await monitorPulseBoardAccount({
              accountId: account.accountId,
              config: ctx.cfg,
              abortSignal: ctx.abortSignal,
            }),
        });
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry) ?? entry.trim(),
      notify: async ({ id, message }) => {
        // Stub: In a real implementation, send `message` as a DM to user `id`
        await sendMessagePulseBoard(id, message);
      },
    },
  },
  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const result = await sendMessagePulseBoard(to, text ?? "", {
        cfg,
        accountId: accountId ?? DEFAULT_ACCOUNT_ID,
      });
      return attachChannelToResult("pulseboard", result);
    },
  },
});
```

**Key design decisions:**
- `capabilities.chatTypes: ["direct", "group"]` enables both DM and board routing.
- `outbound.deliveryMode: "direct"` — messages sent per-call, not batched.
- `textChunkLimit: 4000` — matches PulseBoard spec.
- The `groups` block mirrors IRC's `resolveRequireMention` per-board.
- `pairing` block uses `"pulseBoardUser"` as the ID label.
- No `sendMedia` because `capabilities.media: false`.

