Outbound send stub. Since PulseBoard is fictional, this logs/simulates sending.

```typescript
import { getPulseBoardRuntime } from "./runtime.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardTarget, isBoardTarget } from "./normalize.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string | null;
  replyToId?: string | null;
};

export type SendPulseBoardResult = {
  to: string;
  messageId: string;
};

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" ` +
      `(need apiKey, serverUrl, and username in channels.pulseboard).`,
    );
  }

  const target = normalizePulseBoardTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const payload = text.trim();
  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends.");
  }

  // PulseBoard is fictional: in a real implementation this would POST/send
  // via HTTP or WebSocket to `account.serverUrl` with `account.apiKey`.
  // Stub: generate a deterministic message ID for tracing.
  const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

  runtime.channel.activity.record({
    channel: "pulseboard",
    accountId: account.accountId,
    direction: "outbound",
  });

  return { to: target, messageId };
}
