import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
import { normalizeSecretInputString } from "openclaw/plugin-sdk/secret-input";
import {
  patchTopLevelChannelConfigSection,
  createSetupInputPresenceValidator,  // if available; else manual validate
} from "openclaw/plugin-sdk/setup";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,

  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),

  validateInput: ({ input }) => {
    const typed = input as { useEnv?: boolean; apiKey?: string; serverUrl?: string; username?: string };
    if (!typed.useEnv) {
      if (!typed.apiKey?.trim()) return "PulseBoard requires an API key.";
      if (!typed.serverUrl?.trim()) return "PulseBoard requires a server URL.";
      if (!typed.username?.trim()) return "PulseBoard requires a username.";
    }
    return null;
  },

  applyAccountConfig: ({ cfg, input }) => {
    const typed = input as { useEnv?: boolean; apiKey?: string; serverUrl?: string; username?: string };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      clearFields: typed.useEnv ? ["apiKey"] : undefined,
      patch: {
        ...(typed.useEnv ? {} : { apiKey: typed.apiKey?.trim() }),
        ...(typed.serverUrl?.trim() ? { serverUrl: typed.serverUrl.trim() } : {}),
        ...(typed.username?.trim() ? { username: typed.username.trim() } : {}),
      },
    });
  },
};
