import type { OpenClawConfig } from "../runtime-api.js";

export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  apiKey?: string;           // or SecretInput
  serverUrl?: string;
  username?: string;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  boards?: Record<string, PulseBoardBoardConfig>;
  textChunkLimit?: number;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  // top-level only; single account (no accounts map)
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type ResolvedPulseBoardAccount = {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;  // true when apiKey + serverUrl + username all present
  apiKey: string;
  serverUrl: string;
  username: string;
  config: PulseBoardAccountConfig;
};

export type PulseBoardInboundMessage = {
  messageId: string;
  /** The raw target: board name like "#general" or username like "alice" */
  target: string;
  senderId: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  /** true if message is to a board, false if direct message */
  isBoard: boolean;
};
