### Step 11: `extensions/pulseboard/src/normalize.ts`

```typescript
/** Returns true if target refers to a board (starts with # or "board:") */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalize a raw target string to canonical form.
 * Boards: "#board-name" (# prefix)
 * DMs: "username" (no prefix; strips leading @)
 * Returns undefined for invalid/empty targets.
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;

  let target = trimmed;

  // Strip protocol prefix
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // Board prefix variants
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("#")) {
      target = `#${target}`;
    }
  }

  // DM prefix
  if (target.toLowerCase().startsWith("dm:")) {
    target = target.slice("dm:".length).trim();
    // Strip @ for DMs
    target = target.startsWith("@") ? target.slice(1) : target;
  }

  // Strip leading @ for DMs (but keep # for boards)
  if (target.startsWith("@")) {
    target = target.slice(1);
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }
  return target;
}

const VALID_PULSEBOARD_TARGET = /^[#]?[a-zA-Z0-9_\-]+$/u;

export function looksLikePulseBoardTargetId(raw: string): boolean {
  return VALID_PULSEBOARD_TARGET.test(raw.trim());
}

/** Normalize an allowlist entry to lowercase username or * */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) return "";
  if (value === "*") return "*";
  // Strip @ and protocol
  if (value.startsWith("pulseboard:")) value = value.slice("pulseboard:".length);
  if (value.startsWith("@")) value = value.slice(1);
  return value.trim();
}
