import type { ResolvedPulseBoardAccount, CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorParams = {
  accountId: string;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: unknown;  // PluginRuntime — typed loosely to avoid deep import
  abortSignal?: AbortSignal;
  statusSink?: { setConnected: () => void; setDisconnected: () => void };
  onMessage: (message: PulseBoardInboundMessage) => Promise<void>;
  onError?: (err: Error) => void;
};

/**
 * Monitors a PulseBoard account for inbound messages.
 *
 * PulseBoard is a fictional platform. In a real implementation this would
 * establish a WebSocket connection to `account.serverUrl` and authenticate
 * with `account.apiKey`, receiving events for:
 *   - Direct messages (target = sender username, isBoard = false)
 *   - Board posts (target = "#board-name", isBoard = true)
 *
 * This stub completes immediately. The gateway lifecycle wraps it in
 * `runStoppablePassiveMonitor` which handles reconnect/abort logic.
 */
export async function monitorPulseBoardAccount(
  params: PulseBoardMonitorParams,
): Promise<void> {
  const { accountId, account, abortSignal, onError } = params;

  if (!account.configured) {
    throw new Error(
      `PulseBoard account "${accountId}" is not configured; cannot start monitor.`,
    );
  }

  // Real implementation would open: new WebSocket(`${account.serverUrl}/ws`)
  // and authenticate with: { type: "auth", apiKey: account.apiKey }
  // then dispatch messages via params.onMessage({ ... })
  // and call params.statusSink?.setConnected() / setDisconnected() as appropriate.
  //
  // For now, we park until aborted.
  await new Promise<void>((resolve) => {
    if (abortSignal?.aborted) {
      resolve();
      return;
    }
    const handler = () => resolve();
    abortSignal?.addEventListener("abort", handler, { once: true });
  });
}
