      clearFields: typed.useEnv ? ["apiKey"] : undefined,
      patch: {
        ...(typed.useEnv ? {} : { apiKey: typed.apiKey?.trim() }),
        ...(typed.serverUrl?.trim() ? { serverUrl: typed.serverUrl.trim() } : {}),
        ...(typed.username?.trim() ? { username: typed.username.trim() } : {}),
      },
    });
  },
};
