```typescript
import type { ChannelSetupWizard, ChannelSetupDmPolicy } from "openclaw/plugin-sdk/channel-setup";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
import { hasConfiguredSecretInput, normalizeSecretInputString } from "openclaw/plugin-sdk/secret-input";
import {
  createTopLevelChannelDmPolicy,
  createStandardChannelSetupStatus,
  createTopLevelChannelParsedAllowFromPrompt,
  mergeAllowFromEntries,
  patchTopLevelChannelConfigSection,
  formatDocsLink,
  splitSetupEntries,
  setSetupChannelEnabled,
} from "openclaw/plugin-sdk/setup";
import { normalizePulseBoardAllowEntry } from "./normalize.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import { pulseBoardSetupAdapter } from "./setup-core.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;

const HELP_LINES = [
  "PulseBoard requires an API key, server URL, and username.",
  "Env vars supported: PULSEBOARD_API_KEY, PULSEBOARD_SERVER_URL, PULSEBOARD_USERNAME.",
  "Boards use #board-name format. DMs use @username or username.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by sender username.",
  "Examples: alice, @bob, *",
  "Multiple entries: comma-separated.",
];

function parsePulseBoardAllowFrom(raw: string) {
  const entries = splitSetupEntries(raw)
    .map((e) => normalizePulseBoardAllowEntry(e))
    .filter(Boolean);
  return { entries };
}

const promptPulseBoardAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel,
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  noteTitle: "PulseBoard allowlist",
  noteLines: ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom (username or *)",
  placeholder: "alice, @bob, *",
  parseEntries: parsePulseBoardAllowFrom,
  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  promptAllowFrom: promptPulseBoardAllowFrom,
});

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API key + server URL + username",
    configuredHint: "configured",
    unconfiguredHint: "needs API key + server URL + username",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => resolvePulseBoardAccount({ cfg: cfg as CoreConfig }).configured,
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: HELP_LINES,
  },
  envShortcut: {
    prompt: "PULSEBOARD_API_KEY detected. Use env var?",
    preferredEnvVar: "PULSEBOARD_API_KEY",
    isAvailable: ({ cfg, accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID &&
      Boolean(process.env.PULSEBOARD_API_KEY?.trim()) &&
      !hasConfiguredSecretInput(
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig }).config.apiKey,
      ),
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, clearFields: ["apiKey"], patch: {} }),
  },
  credentials: [
    {
      inputKey: "apiKey",
      providerHint: channel,
      credentialLabel: "API key",
      preferredEnvVar: "PULSEBOARD_API_KEY",
      helpTitle: "PulseBoard API key",
      helpLines: HELP_LINES,
      envPrompt: "PULSEBOARD_API_KEY detected. Use env var?",
      keepPrompt: "PulseBoard API key already configured. Keep it?",
      inputPrompt: "PulseBoard API key",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiKey),
          resolvedValue: normalizeSecretInputString(account.config.apiKey),
          envValue: process.env.PULSEBOARD_API_KEY?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, clearFields: ["apiKey"], patch: {} }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, patch: { apiKey: resolvedValue } }),
    },
  ],
  textInputs: [
    {
      inputKey: "serverUrl",
      message: "PulseBoard server URL",
      placeholder: "https://pulseboard.example.com",
      required: true,
      helpTitle: "PulseBoard server URL",
      helpLines: ["Full URL of your PulseBoard instance (https://)."],
      currentValue: ({ cfg }) => resolvePulseBoardAccount({ cfg: cfg as CoreConfig }).config.serverUrl,
      validate: ({ value }) => {
        const trimmed = String(value ?? "").trim();
        if (!trimmed) return "Required";
        try { new URL(trimmed); return undefined; } catch { return "Invalid URL"; }
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, patch: { serverUrl: String(value).trim() } }),
    },
    {
      inputKey: "username",
      message: "PulseBoard username (bot account)",
      required: true,
      currentValue: ({ cfg }) => resolvePulseBoardAccount({ cfg: cfg as CoreConfig }).config.username,
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, patch: { username: String(value).trim() } }),
    },
  ],
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

export { pulseBoardSetupAdapter };
