        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiKey),
          resolvedValue: normalizeSecretInputString(account.config.apiKey),
          envValue: process.env.PULSEBOARD_API_KEY?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, clearFields: ["apiKey"], patch: {} }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, patch: { apiKey: resolvedValue } }),
    },
  ],
  textInputs: [
    {
      inputKey: "serverUrl",
      message: "PulseBoard server URL",
      placeholder: "https://pulseboard.example.com",
      required: true,
      helpTitle: "PulseBoard server URL",
      helpLines: ["Full URL of your PulseBoard instance (https://)."],
      currentValue: ({ cfg }) => resolvePulseBoardAccount({ cfg: cfg as CoreConfig }).config.serverUrl,
      validate: ({ value }) => {
        const trimmed = String(value ?? "").trim();
        if (!trimmed) return "Required";
        try { new URL(trimmed); return undefined; } catch { return "Invalid URL"; }
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, patch: { serverUrl: String(value).trim() } }),
    },
    {
      inputKey: "username",
      message: "PulseBoard username (bot account)",
      required: true,
      currentValue: ({ cfg }) => resolvePulseBoardAccount({ cfg: cfg as CoreConfig }).config.username,
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, patch: { username: String(value).trim() } }),
    },
  ],
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

export { pulseBoardSetupAdapter };
