Main plugin definition. Follows IRC's structure for group support and Nostr's for single-account.

Key imports (from local barrels and SDK subpaths):
- `createChatChannelPlugin` from `openclaw/plugin-sdk/core`
- `createTopLevelChannelConfigAdapter`, `createScopedDmSecurityResolver` from `openclaw/plugin-sdk/channel-config-helpers`
- `describeAccountSnapshot` from `openclaw/plugin-sdk/account-helpers`
- `createChannelDirectoryAdapter`, `createResolvedDirectoryEntriesLister` from `openclaw/plugin-sdk/directory-runtime`
- The runtime-api barrel for: `dispatchInboundDirectDmWithRuntime`, `resolveInboundDirectDmAccessWithRuntime`, `createPreCryptoDirectDmAuthorizer`, `createComputedAccountStatusAdapter`, `createDefaultChannelRuntimeState`, `buildPassiveChannelStatusSummary`, `buildTrafficStatusSummary`, `runStoppablePassiveMonitor`, `attachChannelToResult`, `createChannelPairingController`, `DEFAULT_ACCOUNT_ID`, `PAIRING_APPROVED_MESSAGE`, `type ChannelPlugin`

**Structure of `channel.ts`:**

```typescript
// imports ...

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg: cfg as CoreConfig }),
  listAccountIds: listPulseBoardAccountIds,
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "apiKey", "serverUrl", "username", "dmPolicy", "allowFrom"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom.map((e) => normalizePulseBoardAllowEntry(String(e))).filter(Boolean),
});

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  normalizeEntry: normalizePulseBoardAllowEntry,
});

// Active connection handles (for outbound replies during gateway lifecycle)
const activeAccounts = new Map<string, { send: (to: string, text: string) => Promise<void>; stop: () => void }>();

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin Board)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "real-time bulletin board with named boards and direct messages.",
      quickstartAllowFrom: true,
    },
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: PulseBoardChannelConfigSchema,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            username: account.username,
          },
        }),
    },
    groups: {
      resolveRequireMention: ({ cfg, accountId, groupId }) => {
        if (!groupId) return true;
        const account = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
        return account.config.boards?.[groupId]?.requireMention ?? true;
      },
      resolveToolPolicy: ({ cfg, accountId, groupId }) => {
        if (!groupId) return undefined;
        // No per-board tool policy for MVP
        return undefined;
      },
    },
    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: looksLikePulseBoardTargetId,
        hint: "<#board-name|@username>",
      },
    },
    resolver: {
      resolveTargets: async ({ inputs, kind }) =>
        inputs.map((input) => {
          const normalized = normalizePulseBoardTarget(input);
          if (!normalized) return { input, resolved: false, note: "invalid PulseBoard target" };
          if (kind === "group" && !isBoardTarget(normalized))
            return { input, resolved: false, note: "expected board target (#board-name)" };
          if (kind === "user" && isBoardTarget(normalized))
            return { input, resolved: false, note: "expected user target" };
          return { input, resolved: true, id: normalized, name: normalized };
        }),
    },
    directory: createChannelDirectoryAdapter({
      listPeers: async (params) => listPulseBoardPeersFromConfig(params),
      listGroups: async (params) => {
        const entries = await listPulseBoardGroupsFromConfig(params);
        return entries.map((entry) => ({ ...entry, name: entry.id }));
      },
    }),
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      buildChannelSummary: ({ snapshot }) =>
        buildPassiveChannelStatusSummary(snapshot, {
          serverUrl: snapshot.serverUrl ?? null,
          username: snapshot.username ?? null,
        }),
      resolveAccountSnapshot: ({ account, runtime }) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
        extra: {
          serverUrl: account.serverUrl,
          username: account.username,
          ...buildTrafficStatusSummary(runtime),
        },
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account as ResolvedPulseBoardAccount;

        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}" ` +
            `(need apiKey, serverUrl, and username in channels.pulseboard).`,
          );
        }

        ctx.log?.info(`[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`);

        const runtime = getPulseBoardRuntime();
        const pairing = createChannelPairingController({
          core: runtime,
          channel: "pulseboard",
          accountId: account.accountId,
        });

        const resolveInboundAccess = async (senderId: string, rawBody: string) =>
          await resolveInboundDirectDmAccessWithRuntime({
            cfg: ctx.cfg,
            channel: "pulseboard",
            accountId: account.accountId,
            dmPolicy: account.config.dmPolicy ?? "pairing",
            allowFrom: account.config.allowFrom,
            senderId,
            rawBody,
            isSenderAllowed: (id, allowFrom) =>
              allowFrom.some((entry) => entry === "*" || entry === normalizePulseBoardAllowEntry(id)),
            runtime: {
              shouldComputeCommandAuthorized: runtime.channel.commands.shouldComputeCommandAuthorized,
              resolveCommandAuthorizedFromAuthorizers:
                runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
            },
          });

        const authorizeSender = createPreCryptoDirectDmAuthorizer({
          resolveAccess: async (senderId) => await resolveInboundAccess(senderId, ""),
          issuePairingChallenge: async ({ senderId, reply }) => {
            await pairing.issueChallenge({
              senderId,
              senderIdLine: `Your PulseBoard username: ${senderId}`,
              sendPairingReply: reply,
              onCreated: () => ctx.log?.debug?.(`[${account.accountId}] pulseboard pairing request sender=${senderId}`),
              onReplyError: (err) => ctx.log?.warn?.(`[${account.accountId}] pulseboard pairing reply failed for ${senderId}: ${String(err)}`),
            });
          },
          onBlocked: ({ senderId, reason }) =>
            ctx.log?.debug?.(`[${account.accountId}] blocked PulseBoard sender ${senderId} (${reason})`),
        });

        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () =>
            await monitorPulseBoardAccount({
              accountId: account.accountId,
              account,
              config: ctx.cfg as CoreConfig,
              runtime,
              abortSignal: ctx.abortSignal,
              onMessage: async (message) => {
                // Group (board) messages
                if (message.isBoard) {
                  // Board messages use group dispatch (not implemented in this MVP stub)
                  ctx.log?.debug?.(`[${account.accountId}] PulseBoard board message on ${message.target} from ${message.senderId}`);
                  return;
                }

                // Direct messages
                const resolvedAccess = await resolveInboundAccess(message.senderId, message.text);
                if (resolvedAccess.access.decision !== "allow") {
                  ctx.log?.warn?.(`[${account.accountId}] dropping PulseBoard DM (${message.senderId}, ${resolvedAccess.access.reason})`);
                  return;
                }

                await dispatchInboundDirectDmWithRuntime({
                  cfg: ctx.cfg,
                  runtime,
                  channel: "pulseboard",
                  channelLabel: "PulseBoard",
                  accountId: account.accountId,
                  peer: { kind: "direct", id: message.senderId },
                  senderId: message.senderId,
                  senderAddress: `pulseboard:${message.senderId}`,
                  recipientAddress: `pulseboard:${account.username}`,
                  conversationLabel: message.senderUsername,
                  rawBody: message.text,
                  messageId: message.messageId,
                  timestamp: message.timestamp,
                  commandAuthorized: resolvedAccess.commandAuthorized,
                  deliver: async (payload) => {
                    const outboundText =
                      payload && typeof payload === "object" && "text" in payload
                        ? String((payload as { text?: string }).text ?? "")
                        : "";
                    if (!outboundText.trim()) return;
                    await sendMessagePulseBoard(message.senderId, outboundText, {
                      cfg: ctx.cfg as CoreConfig,
                      accountId: account.accountId,
                    });
                  },
                  onRecordError: (err) => ctx.log?.error?.(`[${account.accountId}] PulseBoard inbound session error: ${String(err)}`),
                  onDispatchError: (err, info) => ctx.log?.error?.(`[${account.accountId}] PulseBoard ${info.kind} reply failed: ${String(err)}`),
                });
              },
              onError: (err) => ctx.log?.error?.(`[${account.accountId}] PulseBoard monitor error: ${String(err)}`),
            }),
        });
      },
    },
  },

  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: PAIRING_APPROVED_MESSAGE,
      normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry),
      notify: async ({ id, message }) => {
        const normalized = normalizePulseBoardTarget(id);
        if (!normalized || isBoardTarget(normalized)) {
          throw new Error(`invalid PulseBoard pairing id: ${id}`);
        }
        await sendMessagePulseBoard(normalized, message);
      },
    },
  },

  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  outbound: {
    base: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ cfg, to, text, accountId, replyToId }) =>
        await sendMessagePulseBoard(to, text, {
          cfg: cfg as CoreConfig,
          accountId: accountId ?? undefined,
          replyToId: replyToId ?? undefined,
        }),
      sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
        await sendMessagePulseBoard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text, {
          cfg: cfg as CoreConfig,
          accountId: accountId ?? undefined,
          replyToId: replyToId ?? undefined,
        }),
    },
  },
});
```

**Note on `PAIRING_APPROVED_MESSAGE`:** Verify its export location. It may be `openclaw/plugin-sdk/channel-pairing`, `openclaw/plugin-sdk/channel-plugin-common`, or `openclaw/plugin-sdk/extension-shared`. Check `src/plugin-sdk/channel-pairing.ts` and `src/plugin-sdk/channel-plugin-common.ts` before implementing to find the correct subpath.

**Note on `attachedResults` API:** Verify whether `createChatChannelPlugin` takes `outbound: { base: {...}, attachedResults: {...} }` or the flat form `outbound: { deliveryMode, textChunkLimit, sendText, ... }`. Looking at `nostr/src/channel.ts`, the flat form is used directly. IRC uses `base:` + `attachedResults:`. Use the flat form (like Nostr) if `createChatChannelPlugin` doesn't take `base`/`attachedResults` nesting — check IRC vs Nostr calling conventions more carefully.

