### Step 9: `extensions/pulseboard/src/accounts.ts`

Single-account resolution (like Nostr), with env var support.

```typescript
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
import { normalizeSecretInputString } from "openclaw/plugin-sdk/secret-input";
import type { CoreConfig, PulseBoardAccountConfig, ResolvedPulseBoardAccount } from "./types.js";

export function listPulseBoardAccountIds(cfg: CoreConfig): string[] {
  const pbCfg = cfg.channels?.pulseboard as PulseBoardAccountConfig | undefined;
  const hasConfig = Boolean(
    pbCfg?.apiKey || pbCfg?.serverUrl || pbCfg?.username ||
    process.env.PULSEBOARD_API_KEY?.trim() ||
    process.env.PULSEBOARD_SERVER_URL?.trim()
  );
  return hasConfig ? [DEFAULT_ACCOUNT_ID] : [];
}

export function resolveDefaultPulseBoardAccountId(cfg: CoreConfig): string {
  return DEFAULT_ACCOUNT_ID;
}

export function resolvePulseBoardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const pbCfg = (params.cfg.channels?.pulseboard ?? {}) as PulseBoardAccountConfig;
  const baseEnabled = pbCfg.enabled !== false;

  const apiKey =
    normalizeSecretInputString(pbCfg.apiKey) ||
    process.env.PULSEBOARD_API_KEY?.trim() ||
    "";
  const serverUrl =
    pbCfg.serverUrl?.trim() ||
    process.env.PULSEBOARD_SERVER_URL?.trim() ||
    "";
  const username =
    pbCfg.username?.trim() ||
    process.env.PULSEBOARD_USERNAME?.trim() ||
    "";

  return {
    accountId: DEFAULT_ACCOUNT_ID,
    name: pbCfg.name?.trim() || undefined,
    enabled: baseEnabled,
    configured: Boolean(apiKey && serverUrl && username),
    apiKey,
    serverUrl,
    username,
    config: pbCfg,
  };
}
```

**Env vars supported:** `PULSEBOARD_API_KEY`, `PULSEBOARD_SERVER_URL`, `PULSEBOARD_USERNAME`

