/**
 * Normalize a PulseBoard messaging target.
 *
 * Group (board) targets use a '#' prefix:  #announcements, #support
 * Direct message targets are plain usernames: alice, bob  (leading '@' is stripped)
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  if (trimmed.startsWith("#")) {
    // Board target: keep '#' prefix, lowercase the board name.
    const boardName = trimmed.slice(1).trim();
    if (!boardName || !/^[a-zA-Z0-9_-]+$/.test(boardName)) {
      return undefined;
    }
    return `#${boardName.toLowerCase()}`;
  }
  // DM target: strip leading '@' if present, lowercase.
  const candidate = trimmed.startsWith("@") ? trimmed.slice(1).trim() : trimmed;
  if (!candidate || !/^[a-zA-Z0-9_-]+$/.test(candidate)) {
    return undefined;
  }
  return candidate.toLowerCase();
}

/**
 * Returns true if the target is a board (group) target (starts with '#').
 */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Returns true if the raw input looks like a valid PulseBoard target id.
 * Accepts: #board-name, @username, username
 */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  // Board target: #board-name
  if (trimmed.startsWith("#")) {
    const boardName = trimmed.slice(1).trim();
    return boardName.length > 0 && /^[a-zA-Z0-9_-]+$/.test(boardName);
  }
  // DM target: @username or username
  const candidate = trimmed.startsWith("@") ? trimmed.slice(1).trim() : trimmed;
  return candidate.length > 0 && /^[a-zA-Z0-9_-]+$/.test(candidate);
}

/**
 * Normalize an allowlist entry: strip '@' prefix and lowercase.
 * Returns empty string for invalid entries.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  const trimmed = raw.trim().toLowerCase();
  if (!trimmed) {
    return "";
  }
  if (trimmed === "*") {
    return "*";
  }
  const candidate = trimmed.startsWith("@") ? trimmed.slice(1).trim() : trimmed;
  return candidate;
}

