export type SendPulseBoardOptions = {
  account: ResolvedPulseBoardAccount;
  /** Normalized target: #board-name for boards, username for DMs. */
  to: string;
  text: string;
  replyToId?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  to: string;
};

/**
 * Send a message via the PulseBoard API.
 *
 * Stub implementation for the fictional PulseBoard platform. In production,
 * this would POST to `${account.serverUrl}/api/messages` with the apiKey and
 * the resolved target (board or DM recipient).
 */
export async function sendMessagePulseBoard(
  opts: SendPulseBoardOptions,
): Promise<SendPulseBoardResult> {
  // Stub: generate a deterministic-looking message id without network I/O.
  const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  return { messageId, to: opts.to };
}

