/**
 * Inbound message descriptor delivered by the PulseBoard WebSocket stream.
 */
export type PulseBoardInboundMessage = {
  from: string;
  to: string;
  text: string;
  messageId: string;
  timestamp: number;
  /** "group" for board posts, "direct" for DMs. */
  chatType: "direct" | "group";
};

/**
 * Options for the PulseBoard inbound monitor.
 */
export type PulseBoardMonitorOptions = {
  accountId: string;
  apiKey: string;
  serverUrl: string;
  username: string;
  abortSignal?: AbortSignal;
  onMessage?: (msg: PulseBoardInboundMessage) => Promise<void>;
  onError?: (err: Error) => void;
  onConnect?: () => void;
  onDisconnect?: () => void;
};

/**
 * Start the PulseBoard inbound monitor.
 *
 * Stub implementation for the fictional PulseBoard platform. In production,
 * this would open a WebSocket connection to `${serverUrl}/ws` authenticated
 * with the apiKey and stream incoming board posts and direct messages.
 */
export async function monitorPulseBoard(opts: PulseBoardMonitorOptions): Promise<{
  stop: () => void;
}> {
  // Notify caller that the (stub) connection is established.
  opts.onConnect?.();

  return {
    stop() {
      opts.onDisconnect?.();
    },
  };
}

