import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import { patchTopLevelChannelConfigSection } from "openclaw/plugin-sdk/setup";

const channel = "pulseboard" as const;

type PulseBoardSetupInput = {
  useEnv?: boolean;
  apiKey?: string;
  username?: string;
  serverUrl?: string;
};

/** ChannelSetupAdapter for the programmatic (CLI --flag) setup path. */
export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => "default",

  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),

  validateInput: ({ input }) => {
    const typedInput = input as PulseBoardSetupInput;
    if (!typedInput.useEnv) {
      if (!typedInput.apiKey?.trim()) {
        return "PulseBoard requires --api-key or --use-env.";
      }
      if (!typedInput.username?.trim()) {
        return "PulseBoard requires --username.";
