        }
        await sendMessagePulseBoard({ account, to: normalizedId, text: message });
      },
    },
  },

  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  outbound: {
    base: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ cfg, to, text, accountId }) => {
        const account = resolvePulseBoardAccount({
          cfg: cfg as OpenClawConfig,
          accountId: accountId ?? DEFAULT_ACCOUNT_ID,
        });
