import { describe, expect, it } from "vitest";
import { pulseBoardPlugin } from "./channel.js";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./accounts.js";
import {
  isBoardTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardTarget,
} from "./normalize.js";

// ---------------------------------------------------------------------------
// Test helpers
// ---------------------------------------------------------------------------

function makeConfiguredCfg(
  overrides: Record<string, unknown> = {},
): Record<string, unknown> {
  return {
    channels: {
      pulseboard: {
        apiKey: "test-api-key-abc123",
        username: "testbot",
        ...overrides,
      },
    },
  };
}

// ---------------------------------------------------------------------------
// pulseBoardPlugin metadata
// ---------------------------------------------------------------------------

describe("pulseBoardPlugin", () => {
  describe("meta", () => {
    it("has correct id", () => {
      expect(pulseBoardPlugin.id).toBe("pulseboard");
    });

    it("has correct label", () => {
      expect(pulseBoardPlugin.meta.label).toBe("PulseBoard");
    });

    it("has docsPath", () => {
      expect(pulseBoardPlugin.meta.docsPath).toBe("/channels/pulseboard");
    });

    it("has a blurb mentioning boards and direct messages", () => {
      expect(pulseBoardPlugin.meta.blurb).toMatch(/board/i);
      expect(pulseBoardPlugin.meta.blurb).toMatch(/direct/i);
    });
  });

  describe("capabilities", () => {
    it("supports direct messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("direct");
    });

    it("supports group (board) messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("group");
    });

    it("does not support media", () => {
      expect(pulseBoardPlugin.capabilities.media).toBe(false);
    });
  });

  describe("config adapter", () => {
    it("listAccountIds returns empty array for unconfigured", () => {
      const cfg = { channels: {} };
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toEqual([]);
    });

    it("listAccountIds returns default for configured", () => {
      const cfg = makeConfiguredCfg();
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toContain("default");
    });

    it("resolveAccount returns configured account", () => {
      const cfg = makeConfiguredCfg();
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      expect(account.configured).toBe(true);
      expect(account.username).toBe("testbot");
    });

    it("isConfigured returns true for configured account", () => {
      const cfg = makeConfiguredCfg();
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      expect(pulseBoardPlugin.config.isConfigured?.(account)).toBe(true);
    });

    it("isConfigured returns false for unconfigured account", () => {
      const cfg = { channels: { pulseboard: {} } };
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      expect(pulseBoardPlugin.config.isConfigured?.(account)).toBe(false);
    });
  });

  describe("messaging", () => {
    it("looksLikeId recognizes #board target", () => {
      const fn = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;
      expect(fn?.("#announcements")).toBe(true);
    });

    it("looksLikeId recognizes @username DM target", () => {
      const fn = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;
      expect(fn?.("@alice")).toBe(true);
    });

    it("looksLikeId recognizes bare username DM target", () => {
      const fn = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;
      expect(fn?.("alice")).toBe(true);
    });

    it("looksLikeId rejects empty string", () => {
      const fn = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;
      expect(fn?.("")).toBe(false);
    });

    it("normalizeTarget converts #Board to lowercase #board", () => {
      const fn = pulseBoardPlugin.messaging?.normalizeTarget;
      expect(fn?.("#Announcements")).toBe("#announcements");
    });

    it("normalizeTarget strips @ prefix from DM target", () => {
      const fn = pulseBoardPlugin.messaging?.normalizeTarget;
      expect(fn?.("@Alice")).toBe("alice");
    });

    it("normalizeTarget returns undefined for invalid target", () => {
      const fn = pulseBoardPlugin.messaging?.normalizeTarget;
      expect(fn?.("")).toBeUndefined();
    });

    it("hint mentions board and username formats", () => {
      const hint = pulseBoardPlugin.messaging?.targetResolver?.hint;
      expect(hint).toContain("#");
      expect(hint).toContain("username");
    });
  });

  describe("outbound", () => {
    it("has correct text chunk limit", () => {
      expect(pulseBoardPlugin.outbound?.textChunkLimit).toBe(4000);
    });

    it("has direct delivery mode", () => {
      expect(pulseBoardPlugin.outbound?.deliveryMode).toBe("direct");
    });
  });

  describe("pairing", () => {
    it("has pulseBoardUser id label", () => {
      expect(pulseBoardPlugin.pairing?.idLabel).toBe("pulseBoardUser");
    });

    it("normalizeAllowEntry strips @ prefix", () => {
      const fn = pulseBoardPlugin.pairing?.normalizeAllowEntry;
      expect(fn?.("@alice")).toBe("alice");
    });

    it("normalizeAllowEntry lowercases entry", () => {
      const fn = pulseBoardPlugin.pairing?.normalizeAllowEntry;
      expect(fn?.("Alice")).toBe("alice");
    });
  });

  describe("security", () => {
    it("resolveDmPolicy returns pairing by default", () => {
      const fn = pulseBoardPlugin.security?.resolveDmPolicy;
      if (!fn) {
        throw new Error("pulseBoardPlugin.security.resolveDmPolicy is missing");
      }
      const cfg = makeConfiguredCfg();
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      const result = fn({ cfg, account, accountId: "default" });
      expect(result?.policy).toBe("pairing");
    });

    it("resolveDmPolicy respects allowlist policy", () => {
      const fn = pulseBoardPlugin.security?.resolveDmPolicy;
      if (!fn) {
        throw new Error("pulseBoardPlugin.security.resolveDmPolicy is missing");
      }
      const cfg = makeConfiguredCfg({ dmPolicy: "allowlist", allowFrom: ["alice"] });
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      const result = fn({ cfg, account, accountId: "default" });
      expect(result?.policy).toBe("allowlist");
    });
  });

  describe("status", () => {
    it("has default runtime state", () => {
      expect(pulseBoardPlugin.status?.defaultRuntime).toMatchObject({
        accountId: "default",
        running: false,
        lastStartAt: null,
        lastStopAt: null,
        lastError: null,
      });
    });
  });
});

// ---------------------------------------------------------------------------
// normalize helpers
// ---------------------------------------------------------------------------

describe("normalizePulseBoardTarget", () => {
  it("normalizes board target to lowercase with # prefix", () => {
    expect(normalizePulseBoardTarget("#Announcements")).toBe("#announcements");
  });

  it("normalizes DM target by stripping @ and lowercasing", () => {
    expect(normalizePulseBoardTarget("@Alice")).toBe("alice");
  });

  it("normalizes bare username", () => {
    expect(normalizePulseBoardTarget("Bob")).toBe("bob");
  });

  it("returns undefined for empty string", () => {
    expect(normalizePulseBoardTarget("")).toBeUndefined();
  });

  it("returns undefined for # with no board name", () => {
    expect(normalizePulseBoardTarget("#")).toBeUndefined();
  });

  it("returns undefined for board name with invalid characters", () => {
    expect(normalizePulseBoardTarget("#bad board!")).toBeUndefined();
  });
});

describe("looksLikePulseBoardTargetId", () => {
  it("accepts #board-name", () => {
    expect(looksLikePulseBoardTargetId("#support")).toBe(true);
  });

  it("accepts @username", () => {
    expect(looksLikePulseBoardTargetId("@charlie")).toBe(true);
  });

  it("accepts bare username", () => {
    expect(looksLikePulseBoardTargetId("dave")).toBe(true);
  });

  it("rejects empty string", () => {
    expect(looksLikePulseBoardTargetId("")).toBe(false);
  });

  it("rejects username with spaces", () => {
    expect(looksLikePulseBoardTargetId("bad name")).toBe(false);
  });
});

describe("isBoardTarget", () => {
  it("returns true for # prefixed target", () => {
    expect(isBoardTarget("#general")).toBe(true);
  });

  it("returns false for username target", () => {
    expect(isBoardTarget("alice")).toBe(false);
  });
});

describe("normalizePulseBoardAllowEntry", () => {
  it("strips @ prefix", () => {
    expect(normalizePulseBoardAllowEntry("@alice")).toBe("alice");
  });

  it("lowercases entry", () => {
    expect(normalizePulseBoardAllowEntry("Alice")).toBe("alice");
  });

  it("preserves wildcard", () => {
    expect(normalizePulseBoardAllowEntry("*")).toBe("*");
  });

  it("returns empty string for empty input", () => {
    expect(normalizePulseBoardAllowEntry("")).toBe("");
  });
});

// ---------------------------------------------------------------------------
// account helpers
// ---------------------------------------------------------------------------

describe("listPulseBoardAccountIds", () => {
  it("returns empty array when not configured", () => {
    expect(listPulseBoardAccountIds({ channels: {} })).toEqual([]);
  });

  it("returns default when apiKey and username are present", () => {
    const cfg = makeConfiguredCfg();
    expect(listPulseBoardAccountIds(cfg)).toEqual(["default"]);
  });

  it("returns empty array when only enabled is set (no credentials)", () => {
    const cfg = { channels: { pulseboard: { enabled: true } } };
    expect(listPulseBoardAccountIds(cfg)).toEqual([]);
  });
});

describe("resolveDefaultPulseBoardAccountId", () => {
  it("returns default when not configured", () => {
    expect(resolveDefaultPulseBoardAccountId({ channels: {} })).toBe("default");
  });

  it("returns configured defaultAccount when present", () => {
    const cfg = makeConfiguredCfg({ defaultAccount: "work" });
    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("work");
  });
});

describe("resolvePulseBoardAccount", () => {
  it("resolves fully configured account", () => {
    const cfg = makeConfiguredCfg({
      serverUrl: "https://pb.example.com",
      dmPolicy: "pairing",
      boards: ["general"],
    });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.accountId).toBe("default");
    expect(account.configured).toBe(true);
    expect(account.apiKey).toBe("test-api-key-abc123");
    expect(account.username).toBe("testbot");
    expect(account.serverUrl).toBe("https://pb.example.com");
    expect(account.config.boards).toEqual(["general"]);
    expect(account.config.dmPolicy).toBe("pairing");
  });

  it("returns unconfigured account with defaults when nothing set", () => {
    const account = resolvePulseBoardAccount({ cfg: { channels: {} } });
    expect(account.accountId).toBe("default");
    expect(account.configured).toBe(false);
    expect(account.apiKey).toBe("");
    expect(account.username).toBe("");
    expect(account.serverUrl).toBe("https://pulseboard.example.com");
  });

  it("uses apiKey-only config as unconfigured (username required)", () => {
    const cfg = { channels: { pulseboard: { apiKey: "some-key" } } };
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("respects enabled: false", () => {
    const cfg = makeConfiguredCfg({ enabled: false });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.enabled).toBe(false);
    expect(account.configured).toBe(true);
  });

  it("handles custom accountId parameter", () => {
    const cfg = makeConfiguredCfg();
    const account = resolvePulseBoardAccount({ cfg, accountId: "custom" });
    expect(account.accountId).toBe("custom");
  });

  it("preserves allowFrom config", () => {
    const cfg = makeConfiguredCfg({ allowFrom: ["alice", "bob"] });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.config.allowFrom).toEqual(["alice", "bob"]);
  });
});

