import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
  normalizeOptionalAccountId,
} from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../api.js";
import type { PulseBoardAccountConfig, ResolvedPulseBoardAccount } from "./types.js";

const DEFAULT_SERVER_URL = "https://pulseboard.example.com";

function resolveConfiguredDefaultPulseBoardAccountId(cfg: OpenClawConfig): string | undefined {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
  return normalizeOptionalAccountId(pbCfg?.defaultAccount);
}

/**
 * List all configured PulseBoard account IDs.
 * PulseBoard uses a single top-level account; an implicit "default" account is
 * emitted when an apiKey or username is present.
 */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
  const apiKey =
    normalizeSecretInputString(pbCfg?.apiKey) || process.env.PULSEBOARD_API_KEY?.trim() || "";
  const username = pbCfg?.username?.trim() || process.env.PULSEBOARD_USERNAME?.trim() || "";
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId:
      apiKey || username
        ? (resolveConfiguredDefaultPulseBoardAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
        : undefined,
  });
}

/**
 * Get the default PulseBoard account ID.
 */
export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultPulseBoardAccountId(cfg),
  });
}

/**
 * Resolve a PulseBoard account from config, applying env var fallbacks for the
 * default account.
 */
export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg),
  );
  const pbCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;

  const baseEnabled = pbCfg?.enabled !== false;

  // Resolve apiKey: config value first, then env var (default account only).
  const apiKey =
    normalizeSecretInputString(pbCfg?.apiKey) ||
    (accountId === DEFAULT_ACCOUNT_ID ? (process.env.PULSEBOARD_API_KEY?.trim() ?? "") : "");

  // Resolve serverUrl: config value first, then env var, then default.
  const serverUrl =
    pbCfg?.serverUrl?.trim() ||
    (accountId === DEFAULT_ACCOUNT_ID
      ? (process.env.PULSEBOARD_SERVER_URL?.trim() ?? DEFAULT_SERVER_URL)
      : DEFAULT_SERVER_URL);

  // Resolve username: config value first, then env var (default account only).
  const username =
    pbCfg?.username?.trim() ||
    (accountId === DEFAULT_ACCOUNT_ID ? (process.env.PULSEBOARD_USERNAME?.trim() ?? "") : "");

  const configured = Boolean(apiKey && username);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: baseEnabled,
    configured,
    apiKey,
    serverUrl,
    username,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      apiKey: pbCfg?.apiKey,
      serverUrl: pbCfg?.serverUrl,
      username: pbCfg?.username,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
      boards: pbCfg?.boards,
    },
  };
}

import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { buildPassiveChannelStatusSummary } from "openclaw/plugin-sdk/extension-shared";
import {
  type ChannelPlugin,
  buildChannelConfigSchema,
  collectStatusIssuesFromLastError,
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
  DEFAULT_ACCOUNT_ID,
  formatPairingApproveHint,
  PAIRING_APPROVED_MESSAGE,
  type OpenClawConfig,
} from "../runtime-api.js";
import { PulseBoardConfigSchema } from "./config-schema.js";
import { monitorPulseBoard } from "./monitor.js";
import {
  isBoardTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardTarget,
} from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendMessagePulseBoard } from "./send.js";
import { pulseBoardSetupAdapter, pulseBoardSetupWizard } from "./setup-surface.js";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
  resolveDefaultPulseBoardAccountId,
  type ResolvedPulseBoardAccount,
} from "./accounts.js";

// Track active monitor handles so we can stop them on shutdown.
const activeMonitors = new Map<string, { stop: () => void }>();

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  approveHint: formatPairingApproveHint("pulseboard"),
  normalizeEntry: (raw) => normalizePulseBoardAllowEntry(raw),
});

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
  listAccountIds: listPulseBoardAccountIds,
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "defaultAccount", "apiKey", "serverUrl", "username", "dmPolicy", "allowFrom", "boards"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((entry) => normalizePulseBoardAllowEntry(String(entry)))
      .filter(Boolean),
});

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging with named boards and direct messages",
      order: 60,
      quickstartAllowFrom: true,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: buildChannelConfigSchema(PulseBoardConfigSchema),
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            username: account.username,
            serverUrl: account.serverUrl,
          },
        }),
    },
    messaging: {
      normalizeTarget: (target) => normalizePulseBoardTarget(target),
      targetResolver: {
        looksLikeId: (input) => looksLikePulseBoardTargetId(input),
        hint: "<#board-name|username|@username>",
      },
    },
    status: {
      ...createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        collectStatusIssues: (accounts) =>
          collectStatusIssuesFromLastError("pulseboard", accounts),
        buildChannelSummary: ({ snapshot }) =>
          buildPassiveChannelStatusSummary(snapshot),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            username: account.username,
            serverUrl: account.serverUrl,
          },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}" (need apiKey and username in channels.pulseboard).`,
          );
        }
        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (user: ${account.username}, server: ${account.serverUrl})`,
        );

        const monitor = await monitorPulseBoard({
          accountId: account.accountId,
          apiKey: account.apiKey,
          serverUrl: account.serverUrl,
          username: account.username,
          abortSignal: ctx.abortSignal,
          onConnect: () => {
            ctx.log?.debug?.(`[${account.accountId}] PulseBoard WebSocket connected`);
          },
          onDisconnect: () => {
            ctx.log?.debug?.(`[${account.accountId}] PulseBoard WebSocket disconnected`);
          },
          onError: (err) => {
            ctx.log?.error?.(`[${account.accountId}] PulseBoard monitor error: ${err.message}`);
          },
        });

        activeMonitors.set(account.accountId, monitor);
        ctx.log?.info(`[${account.accountId}] PulseBoard provider started`);

        return {
          stop: () => {
            monitor.stop();
            activeMonitors.delete(account.accountId);
            ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
          },
        };
      },
    },
  },

  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: PAIRING_APPROVED_MESSAGE,
      normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry),
      notify: async ({ id, message }) => {
        const normalizedId = normalizePulseBoardAllowEntry(id);
        if (!normalizedId) {
          throw new Error(`invalid PulseBoard pairing id: ${id}`);
        }
        // Send the approval DM via the active default account monitor.
        const runtime = getPulseBoardRuntime();
        const cfg = runtime.config.loadConfig() as OpenClawConfig;
        const account = resolvePulseBoardAccount({ cfg });
        if (!account.configured) {
          throw new Error("PulseBoard account not configured for pairing notify");
        }
        await sendMessagePulseBoard({ account, to: normalizedId, text: message });
      },
    },
  },

  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  outbound: {
    base: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ cfg, to, text, accountId }) => {
        const account = resolvePulseBoardAccount({
          cfg: cfg as OpenClawConfig,
          accountId: accountId ?? DEFAULT_ACCOUNT_ID,
        });
        if (!account.configured) {
          throw new Error(`PulseBoard account "${account.accountId}" is not configured`);
        }
        const result = await sendMessagePulseBoard({ account, to, text: text ?? "" });
        return attachChannelToResult("pulseboard", {
          to: result.to,
          messageId: result.messageId,
        });
      },
    },
  },
});

/**
 * Returns whether the given target is a board (group) target.
 * Exported for use by tests and external callers.
 */
export { isBoardTarget };

