tool_use_result.originalFile:
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
import {
  hasConfiguredSecretInput,
  normalizeSecretInputString,
} from "openclaw/plugin-sdk/secret-input";
import {
  createStandardChannelSetupStatus,
  createTopLevelChannelDmPolicy,
  createTopLevelChannelParsedAllowFromPrompt,
  formatDocsLink,
  mergeAllowFromEntries,
  parseSetupEntriesWithParser,
  patchTopLevelChannelConfigSection,
  splitSetupEntries,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
} from "./accounts.js";
import { normalizePulseBoardAllowEntry } from "./normalize.js";
import { pulseBoardSetupAdapter } from "./setup-core.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP_LINES = [
  "Provide a PulseBoard API key and your username to authenticate.",
  "The server URL is optional; leave blank to use the default.",
  "Env vars supported (default account): PULSEBOARD_API_KEY, PULSEBOARD_USERNAME, PULSEBOARD_SERVER_URL.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by sender username.",
  "Examples:",
  "- alice",
  "- @bob",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function parsePulseBoardAllowFrom(raw: string): { entries: string[]; error?: string } {
  return parseSetupEntriesWithParser(raw, (entry) => {
    const normalized = normalizePulseBoardAllowEntry(entry);
    if (!normalized) {
      return { error: `Invalid PulseBoard username: ${entry}` };
    }
    return { value: normalized };
  });
}

const promptPulseBoardAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel,
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  noteTitle: "PulseBoard allowlist",
  noteLines: PULSEBOARD_ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom (username)",
  placeholder: "alice, @bob",
  parseEntries: parsePulseBoardAllowFrom,
  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => {
    const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
      | { dmPolicy?: string }
      | undefined;
    return (pbCfg?.dmPolicy as "pairing" | "allowlist" | "open" | "disabled" | undefined) ??
      "pairing";
  },
  promptAllowFrom: promptPulseBoardAllowFrom,
});

function parseBoardNames(raw: string): { boards: string[]; error?: string } {
  const entries = splitSetupEntries(raw);
  const boards: string[] = [];
  for (const entry of entries) {
    if (!/^[a-zA-Z0-9_-]+$/.test(entry)) {
      return {
        boards: [],
        error: `Invalid board name "${entry}". Use letters, numbers, hyphens, or underscores.`,
      };
    }
    boards.push(entry.toLowerCase());
  }
  return { boards: [...new Set(boards)] };
}

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,

  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API key and username",
    configuredHint: "configured",
    unconfiguredHint: "needs API key and username",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => resolvePulseBoardAccount({ cfg }).configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseBoardAccount({ cfg });
      const lines: string[] = [];
      if (account.username) {
        lines.push(`Username: ${account.username}`);
      }
      if (account.config.boards?.length) {
        lines.push(`Boards: ${account.config.boards.join(", ")}`);
      }
      return lines;
    },
  }),

  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },

  envShortcut: {
    prompt: "PULSEBOARD_API_KEY detected. Use env var?",
    preferredEnvVar: "PULSEBOARD_API_KEY",
    isAvailable: ({ cfg, accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID &&
      Boolean(process.env.PULSEBOARD_API_KEY?.trim()) &&
      !hasConfiguredSecretInput(resolvePulseBoardAccount({ cfg, accountId }).config.apiKey),
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({
        cfg,
        channel,
        enabled: true,
        clearFields: ["apiKey"],
        patch: {},
      }),
  },

  credentials: [
    {
      inputKey: "apiKey",
      providerHint: channel,
      credentialLabel: "API key",
      preferredEnvVar: "PULSEBOARD_API_KEY",
      helpTitle: "PulseBoard API key",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_KEY detected. Use env var?",
      keepPrompt: "PulseBoard API key already configured. Keep it?",
      inputPrompt: "PulseBoard API key",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiKey),
          resolvedValue: normalizeSecretInputString(account.config.apiKey),
          envValue: process.env.PULSEBOARD_API_KEY?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: ["apiKey"],
          patch: {},
        }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiKey: resolvedValue },
        }),
    },
  ],

  textInputs: [
    {
      inputKey: "username",
      message: "PulseBoard username",
      placeholder: "yourname",
      required: true,
      applyEmptyValue: false,
      helpTitle: "PulseBoard username",
      helpLines: ["Your PulseBoard account username.", "Env var: PULSEBOARD_USERNAME."],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.config.username?.trim() ?? "";
      },
      keepPrompt: (value) => `Username set (${value}). Keep it?`,
      validate: ({ value }) => {
        if (!value.trim()) {
          return "Username is required.";
        }
        if (!/^[a-zA-Z0-9_-]+$/.test(value.trim())) {
          return "Username may only contain letters, numbers, hyphens, or underscores.";
        }
        return undefined;
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { username: value.trim() },
        }),
    },
    {
      inputKey: "boards",
      message: "Boards to subscribe to (comma-separated, optional)",
      placeholder: "announcements, support",
      required: false,
      applyEmptyValue: true,
      helpTitle: "PulseBoard boards",
      helpLines: [
        "Enter board names (without #) to receive inbound posts.",
        "Leave blank to skip board subscriptions.",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.config.boards?.join(", ") ?? "";
      },
      keepPrompt: (value) => `Boards set (${value}). Keep them?`,
      validate: ({ value }) => {
        if (!value.trim()) {
          return undefined;
        }
        return parseBoardNames(value).error;
      },
      applySet: async ({ cfg, value }) => {
        const boardResult = value.trim() ? parseBoardNames(value) : { boards: [] };
        return patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: boardResult.boards.length > 0 ? undefined : ["boards"],
          patch: boardResult.boards.length > 0 ? { boards: boardResult.boards } : {},
        });
      },
    },
  ],

  dmPolicy: pulseBoardDmPolicy,

  disable: (cfg) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: { enabled: false },
    }),
};

export { pulseBoardSetupAdapter };
export { listPulseBoardAccountIds };
